import{_ as a,o,c as t,a2 as r}from"./chunks/framework.DG4H4-xE.js";const g=JSON.parse('{"title":"Работа с Telegram-ботом","description":"","frontmatter":{},"headers":[],"relativePath":"guide/bot-usage.md","filePath":"guide/bot-usage.md"}'),l={name:"guide/bot-usage.md"};function i(s,e,n,c,d,p){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="работа-с-telegram-ботом" tabindex="-1">Работа с Telegram-ботом <a class="header-anchor" href="#работа-с-telegram-ботом" aria-label="Permalink to &quot;Работа с Telegram-ботом&quot;">​</a></h1><p>Вся магия SREBot разворачивается в интерфейсе вашего корпоративного или личного Telegram-чата.</p><h2 id="чтение-алертов-из-чата" tabindex="-1">Чтение алертов из чата <a class="header-anchor" href="#чтение-алертов-из-чата" aria-label="Permalink to &quot;Чтение алертов из чата&quot;">​</a></h2><p>Вместо того чтобы настраивать сложные вебхуки, SREBot работает напрямую с вашими уже существующими уведомлениями. Когда ваш Alertmanager (или другой бот, транслирующий алерты) присылает сообщение в чат с заголовками вроде <code>🚨 Alerts Firing:</code>, SREBot:</p><ol><li>Читает текст сообщения.</li><li>Ищет блоки <strong>Labels</strong> и <strong>Annotations</strong>.</li><li>Парсит метаданные (<code>alertname</code>, <code>cluster</code>, <code>namespace</code>, <code>severity</code>) и создает <strong>Incident Log</strong> объект в базе данных.</li></ol><p>Если от одной и той же системы с одним и тем же отпечатком (fingerprint) приходят повторные сообщения в чат, SREBot группирует их (дедупликация) и проводит только один анализ.</p><h2 id="формат-ответа-rca-report" tabindex="-1">Формат ответа (RCA Report) <a class="header-anchor" href="#формат-ответа-rca-report" aria-label="Permalink to &quot;Формат ответа (RCA Report)&quot;">​</a></h2><p>Как только AI агент соберет нужные данные из метрик (Prometheus) и логов (Elasticsearch), бот отправит итоговое сообщение. <strong>Сообщение придет ответом (reply)</strong> на оригинальный текст Alertmanager, чтобы было понятно, какую именно проблему расследовал бот.</p><p><b style="font-size:1.2em;">🔍 Root Cause Analysis</b></p><p><b>Alert:</b> CPUThrottlingHigh <br><b>Cluster:</b> <code>prod-cluster</code> | <b>Namespace:</b> <code>payment-service</code></p><p><b>📊 Findings:</b></p><ul><li>За последние 15 минут потребление CPU достигло 99%.</li><li>В логах обнаружены частые ошибки <code>OutOfMemory</code> и перезапуски сборщика мусора.</li><li>База данных начала отвечать с задержкой 5 секунд по причине пула соединений.</li></ul><p><b>🔧 Likely Cause:</b> Низкий лимит CPU на поде <code>payment-service</code> привел к массивному throttling-у, что вызвало каскадную деградацию сервиса и таймауты работы с БД.</p><p><b>💡 Recommended Actions:</b></p><ol><li>Увеличьте <code>resources.limits.cpu</code> в манифесте пода <code>payment-service</code>.</li><li>Перезапустите под.</li></ol><hr><p><em>(Пример вывода SREBot)</em></p><h2 id="лимиты-и-баланс" tabindex="-1">Лимиты и баланс <a class="header-anchor" href="#лимиты-и-баланс" aria-label="Permalink to &quot;Лимиты и баланс&quot;">​</a></h2><p>Обратите внимание: Если в момент появления алерта в чате ваш баланс равен нулю (или ниже), бот <strong>не будет</strong> запускать AI агента. Вы получите стандартное текстовое уведомление о недостаточном балансе платформы, и анализ инцидента будет отменен. Дополнительную информацию о тарифах можно получить в разделе <a href="/guide/dashboard">Веб-дашборд и Биллинг</a>.</p>',19)])])}const u=a(l,[["render",i]]);export{g as __pageData,u as default};
